/**
 * Unit tests for the server extension host's ActionDispatcher.
 *
 * ModuleHost owns worker loading, evaluation, and termination and has its own
 * real-worker isolation suite. These dispatcher tests inject that documented
 * seam so resolution, status mapping, permits, rate limits, and cache epochs stay
 * deterministic without starting a fresh worker for every policy assertion.
 */
import { afterAll, beforeAll, describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import {
	ActionDispatcher,
	ActionError,
	resolveActionToolManager,
	type ActionHandlerCtx,
	type ActionToolLocationResolver,
} from "../../src/server/extension-host/action-dispatcher.ts";
import type { InvokeRequest, ModuleHost } from "../../src/server/extension-host/module-host-worker.ts";
import { installScopedMemoryFs } from "./helpers/scoped-memory-fs.ts";
import { makeTmpDir } from "../../tests/helpers/tmp.ts";

type InvokeFake = (request: InvokeRequest, timeoutMs?: number) => unknown | Promise<unknown>;
type RecordedHost = { host: ModuleHost; calls: InvokeRequest[] };

function fakeModuleHost(invoke: InvokeFake): RecordedHost {
	const calls: InvokeRequest[] = [];
	return {
		calls,
		host: {
			invoke: async (request: InvokeRequest, timeoutMs?: number) => {
				calls.push(request);
				return await invoke(request, timeoutMs);
			},
			dispose: () => {},
		} as unknown as ModuleHost,
	};
}

function deferred<T = unknown>() {
	let resolve!: (value: T) => void;
	let reject!: (reason: unknown) => void;
	const promise = new Promise<T>((res, rej) => { resolve = res; reject = rej; });
	return { promise, resolve, reject };
}

let tmp: string;
let restoreFs: (() => void) | undefined;

function resolver(
	baseDir: string,
	groupDir: string,
	opts: { tool?: string; actionsModule?: string } = {},
): ActionToolLocationResolver {
	const tool = opts.tool ?? "sample_action";
	return {
		resolveToolLocation: (name) =>
			name === tool ? { baseDir, groupDir, actionsModule: opts.actionsModule } : undefined,
	};
}

function writeTool(baseDir: string, groupDir: string, opts: { yaml?: string; actionsJs?: string; moduleName?: string } = {}): void {
	const dir = path.join(baseDir, groupDir);
	fs.mkdirSync(dir, { recursive: true });
	const moduleName = opts.moduleName ?? "actions.js";
	fs.writeFileSync(
		path.join(dir, "sample_action.yaml"),
		opts.yaml ?? `name: sample_action\ndescription: demo\ngroup: Demo\nactions:\n  module: ${moduleName}\n  names: [retry]\n`,
	);
	if (opts.actionsJs !== undefined) fs.writeFileSync(path.join(dir, moduleName), opts.actionsJs);
}

const ctx = (): ActionHandlerCtx => ({
	host: {} as ActionHandlerCtx["host"],
	sessionId: "sess-1",
	toolUseId: "tu-1",
	tool: "sample_action",
});

beforeAll(() => {
	restoreFs = installScopedMemoryFs();
	tmp = makeTmpDir("ext-host-dispatch-");
});
afterAll(() => {
	fs.rmSync(tmp, { recursive: true, force: true });
	restoreFs?.();
});

describe("ActionDispatcher — resolution + happy path", () => {
	it("loads actions.js from the winning provider dir and returns the handler result", async () => {
		const base = path.join(tmp, "case-happy");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => ({ ok: true, echo: request.arg, tool: request.ctx.tool }));
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), { n: 7 }), { ok: true, echo: { n: 7 }, tool: "sample_action" });
		assert.equal(recorded.calls[0].member, "retry");
		assert.match(recorded.calls[0].url, /actions\.js/);
	});

	it("honors a custom actions.module path from the YAML", async () => {
		const base = path.join(tmp, "case-custom-module");
		writeTool(base, "demo", { moduleName: "handlers.js", actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost(() => ({ from: "handlers.js" }));
		const d = new ActionDispatcher(resolver(base, "demo", { actionsModule: "handlers.js" }), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { from: "handlers.js" });
		assert.match(recorded.calls[0].url, /handlers\.js/);
	});

	it("supports a default-exported actions module", async () => {
		const base = path.join(tmp, "case-default-export");
		writeTool(base, "demo", { actionsJs: "export default { actions: {} };" });
		const recorded = fakeModuleHost(() => ({ via: "default" }));
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { via: "default" });
	});

	it("loads from whatever (winning) provider dir it is handed (precedence/shadowing)", async () => {
		const builtin = path.join(tmp, "case-precedence", "builtin");
		const pack = path.join(tmp, "case-precedence", "market-packs", "demo", "tools-root");
		writeTool(builtin, "demo", { actionsJs: "export const actions = {};" });
		writeTool(pack, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => ({ from: request.url.includes("market-packs") ? "pack" : "builtin" }));
		const d = new ActionDispatcher(resolver(pack, "demo"), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { from: "pack" });
		assert.match(recorded.calls[0].url, /market-packs/);
	});
});

describe("ActionDispatcher — error isolation + blast-radius", () => {
	it("unknown tool provider → 404", async () => {
		const recorded = fakeModuleHost(() => assert.fail("unknown tools must not reach ModuleHost"));
		const d = new ActionDispatcher({ resolveToolLocation: () => undefined }, { rate: null, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("nope", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 404);
		assert.equal(recorded.calls.length, 0);
	});

	it("missing actions module file → 404", async () => {
		const base = path.join(tmp, "case-missing-module");
		writeTool(base, "demo");
		const recorded = fakeModuleHost(() => assert.fail("missing modules must not be invoked"));
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 404);
		assert.equal(recorded.calls.length, 0);
	});

	it("unknown action name → 404", async () => {
		const base = path.join(tmp, "case-unknown-action");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost(() => { throw new ActionError(404, "unknown action"); });
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("sample_action", "doesnotexist", ctx(), {}), (e) => e instanceof ActionError && e.status === 404);
	});

	it("inherited property name (constructor/toString) is rejected as unknown, never executed", async () => {
		const base = path.join(tmp, "case-inherited");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => {
			if (request.member === "retry") return { ok: 1 };
			throw new ActionError(404, "unknown action");
		});
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		for (const evil of ["constructor", "toString", "hasOwnProperty", "__proto__"]) {
			await assert.rejects(() => d.dispatch("sample_action", evil, ctx(), {}), (e) => e instanceof ActionError && e.status === 404);
		}
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { ok: 1 });
		assert.deepEqual(recorded.calls.map((call) => call.member), ["constructor", "toString", "hasOwnProperty", "__proto__", "retry"]);
	});

	it("module without an actions export → 500", async () => {
		const base = path.join(tmp, "case-no-export");
		writeTool(base, "demo", { actionsJs: "export const notActions = {};" });
		const recorded = fakeModuleHost(() => { throw new ActionError(500, "module has no actions export"); });
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 500);
	});

	it("handler throw → 500 and the dispatcher survives (process not torn down)", async () => {
		const base = path.join(tmp, "case-throw");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		let invocation = 0;
		const recorded = fakeModuleHost(() => {
			if (invocation++ === 0) throw new Error("boom");
			return { ok: 1 };
		});
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 500 && /boom/.test(e.message));
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { ok: 1 });
	});

	it("handler exceeding the per-call timeout → 504, slot released", async () => {
		const base = path.join(tmp, "case-timeout");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		let invocation = 0;
		const recorded = fakeModuleHost(() => {
			if (invocation++ === 0) throw new ActionError(504, "module host timed out and terminated worker");
			return { ok: 1 };
		});
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, maxConcurrent: 1, moduleHost: recorded.host });
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 504);
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { ok: 1 });
	});

	it("global concurrency cap → 429 for the over-cap call", async () => {
		const base = path.join(tmp, "case-concurrency");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const firstResult = deferred<{ ok: number }>();
		const recorded = fakeModuleHost(() => firstResult.promise);
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, maxConcurrent: 1, moduleHost: recorded.host });
		const first = d.dispatch("sample_action", "retry", ctx(), {});
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 429);
		firstResult.resolve({ ok: 1 });
		assert.deepEqual(await first, { ok: 1 });
	});

	it("a hung handler is TERMINATED on timeout (Slice C3) → its permit is released, NOT held forever", async () => {
		const base = path.join(tmp, "case-permit-terminate");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const pending: ReturnType<typeof deferred>[] = [];
		let terminated = false;
		const recorded = fakeModuleHost(() => {
			if (terminated) throw new ActionError(504, "terminated");
			const call = deferred();
			pending.push(call);
			return call.promise;
		});
		const maxConcurrent = 3;
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: null, maxConcurrent, moduleHost: recorded.host });
		const hung = Array.from({ length: maxConcurrent }, () => d.dispatch("sample_action", "retry", ctx(), {}));
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 429);
		terminated = true;
		for (const call of pending) call.reject(new ActionError(504, "terminated"));
		await Promise.all(hung.map((promise) => assert.rejects(() => promise, (e) => e instanceof ActionError && e.status === 504)));
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 504);
	});

	it("a hung MODULE EVAL (top-level await that never settles) is TERMINATED in the worker on timeout → 504, permit released", async () => {
		const base = path.join(tmp, "case-hung-eval");
		writeTool(base, "demo", { moduleName: "actions.mjs", actionsJs: "await new Promise(() => {});" });
		const pending = deferred();
		let terminated = false;
		const recorded = fakeModuleHost(() => terminated ? Promise.reject(new ActionError(504, "module evaluation terminated")) : pending.promise);
		const d = new ActionDispatcher(resolver(base, "demo", { actionsModule: "actions.mjs" }), { rate: null, maxConcurrent: 1, moduleHost: recorded.host });
		const hung = d.dispatch("sample_action", "retry", ctx(), {});
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 429);
		terminated = true;
		pending.reject(new ActionError(504, "module evaluation terminated"));
		await assert.rejects(() => hung, (e) => e instanceof ActionError && e.status === 504);
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 504);
	});

	it("per-session rate limit → 429 once the bucket drains", async () => {
		const base = path.join(tmp, "case-rate");
		writeTool(base, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost(() => ({ ok: 1 }));
		const d = new ActionDispatcher(resolver(base, "demo"), { rate: { capacity: 2, refillPerSec: 0 }, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { ok: 1 });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { ok: 1 });
		await assert.rejects(() => d.dispatch("sample_action", "retry", ctx(), {}), (e) => e instanceof ActionError && e.status === 429);
		assert.equal(recorded.calls.length, 2);
	});
});

describe("resolveActionToolManager — project-scope precedence (no split-brain, design §4b)", () => {
	it("returns the PROJECT tool manager when one is present (project pack wins)", () => {
		const server = { id: "server" } as unknown as ActionToolLocationResolver;
		const project = { id: "project" } as unknown as ActionToolLocationResolver;
		assert.equal(resolveActionToolManager(server, project), project);
	});

	it("falls back to the SERVER manager when there is no project (server/global scope)", () => {
		const server = { id: "server" } as unknown as ActionToolLocationResolver;
		assert.equal(resolveActionToolManager(server, undefined), server);
		assert.equal(resolveActionToolManager(server, null), server);
	});

	it("dispatch honors the per-call (project) resolver over the constructor (server) one", async () => {
		const builtin = path.join(tmp, "case-percall", "builtin");
		const projectPack = path.join(tmp, "case-percall", "project-pack");
		writeTool(builtin, "demo", { actionsJs: "export const actions = {};" });
		writeTool(projectPack, "demo", { actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => ({ from: request.url.includes("project-pack") ? "project" : "server" }));
		const d = new ActionDispatcher(resolver(builtin, "demo"), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { from: "server" });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}, resolver(projectPack, "demo")), { from: "project" });
		assert.match(recorded.calls[1].url, /project-pack/);
	});
});

describe("ActionDispatcher — cache + invalidation", () => {
	it("reuses a hot module, and invalidate() picks up updated handler source", async () => {
		const base = path.join(tmp, "case-invalidate");
		const modulePath = path.join(base, "demo", "actions.mjs");
		writeTool(base, "demo", { moduleName: "actions.mjs", actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => ({ v: request.epoch + 1 }));
		const d = new ActionDispatcher(resolver(base, "demo", { actionsModule: "actions.mjs" }), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { v: 1 });
		const hotUrl = recorded.calls[0].url;
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { v: 1 });
		assert.equal(recorded.calls[1].url, hotUrl);
		fs.writeFileSync(modulePath, "export const actions = { retry: async () => ({ v: 2 }) };" );
		d.invalidate();
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { v: 2 });
		assert.notEqual(recorded.calls[2].url, hotUrl);
	});

	it("invalidate() serves fresh source even under an IDENTICAL (coarse) mtime — the epoch re-busts the worker import URL", async () => {
		const base = path.join(tmp, "case-coarse-mtime");
		const modulePath = path.join(base, "demo", "actions.mjs");
		writeTool(base, "demo", { moduleName: "actions.mjs", actionsJs: "export const actions = {};" });
		const recorded = fakeModuleHost((request) => ({ v: request.epoch + 1 }));
		const d = new ActionDispatcher(resolver(base, "demo", { actionsModule: "actions.mjs" }), { rate: null, moduleHost: recorded.host });
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { v: 1 });
		const firstUrl = recorded.calls[0].url;
		fs.writeFileSync(modulePath, "export const actions = { retry: async () => ({ v: 2 }) };" );
		d.invalidate();
		assert.deepEqual(await d.dispatch("sample_action", "retry", ctx(), {}), { v: 2 });
		assert.match(firstUrl, /[?&]e=0/);
		assert.match(recorded.calls[1].url, /[?&]e=1/);
		assert.notEqual(recorded.calls[1].url, firstUrl);
	});
});
